sys_variable_value.value:
(function execute(inputs, outputs) {
    // 1. Get the record
    var requestGR = inputs.req_gr;
    
    // 2. Call our Script Include (We will create this in the next step)
    // Note: If you haven't created the Script Include yet, this line is a placeholder.
    var helper = new TimetableHelper(); 
    var result = helper.generateSchedule(requestGR);
    
    // 3. Log for debugging
    gs.info("AI Timetable Generation Result: " + result);

})(inputs, outputs);

